import { MakeLogicType, afterMount, connect, kea, path, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import { projectLogic } from 'scenes/projectLogic'

import { hogFlowsReputationRetrieve } from 'products/workflows/frontend/generated/api'
import type {
    EmailReputationSnapshotApi,
    TeamEmailReputationResponseApi,
    WorkflowEmailReputationSnapshotApi,
} from 'products/workflows/frontend/generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface workflowsReputationLogicValues {
    currentProjectId: number | null // projectLogic
    reputationResponse: TeamEmailReputationResponseApi | null
    reputationResponseLoading: boolean
    teamReputation: EmailReputationSnapshotApi | null
    workflowSnapshots: readonly WorkflowEmailReputationSnapshotApi[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface workflowsReputationLogicActions {
    loadReputation: () => any
    loadReputationFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadReputationSuccess: (
        reputationResponse: TeamEmailReputationResponseApi | null,
        payload?: any
    ) => {
        reputationResponse: TeamEmailReputationResponseApi | null
        payload?: any
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface workflowsReputationLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        teamReputation: (reputationResponse: TeamEmailReputationResponseApi | null) => EmailReputationSnapshotApi | null
        workflowSnapshots: (
            reputationResponse: TeamEmailReputationResponseApi | null
        ) => readonly WorkflowEmailReputationSnapshotApi[]
    }
}

export type workflowsReputationLogicType = MakeLogicType<
    workflowsReputationLogicValues,
    workflowsReputationLogicActions,
    Record<string, any>,
    workflowsReputationLogicMeta
>

export const workflowsReputationLogic = kea<workflowsReputationLogicType>([
    path(['products', 'workflows', 'frontend', 'Workflows', 'Reputation', 'workflowsReputationLogic']),
    connect(() => ({
        values: [projectLogic, ['currentProjectId']],
    })),
    loaders(({ values }) => ({
        reputationResponse: [
            null as TeamEmailReputationResponseApi | null,
            {
                loadReputation: async () => {
                    if (!values.currentProjectId) {
                        return null
                    }
                    return await hogFlowsReputationRetrieve(String(values.currentProjectId))
                },
            },
        ],
    })),
    selectors({
        teamReputation: [
            (s) => [s.reputationResponse],
            (response: TeamEmailReputationResponseApi | null): EmailReputationSnapshotApi | null =>
                response?.reputation ?? null,
        ],
        workflowSnapshots: [
            (s) => [s.reputationResponse],
            (response: TeamEmailReputationResponseApi | null): readonly WorkflowEmailReputationSnapshotApi[] =>
                response?.workflows ?? [],
        ],
    }),
    afterMount(({ actions }) => {
        actions.loadReputation()
    }),
])
